import java.util.Scanner;

public class SafeBufferCopy {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Use a safe method to copy input into a bounded buffer
        char[] buffer = new char[10];
        int length = Math.min(name.length(), buffer.length);

        for (int i = 0; i < length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Your name is: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
